     openai: {
       images: [{
         revisedPrompt?: string,
         created?: number,
         size?: string,
         quality?: string,
         background?: string,
         outputFormat?: string,
         imageTokens?: number,
         textTokens?: number,
       }]
     }
   }
   ```

