53	  async doGenerate({
54	    prompt,
55	    n,
56	    size,
57	    aspectRatio,
58	    seed,
59	    providerOptions,
60	    headers,
61	    abortSignal,
62	    files,
63	    mask,
64	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
65	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
66	  > {
67	    const warnings: Array<SharedV3Warning> = [];
68	
69	    if (seed != null) {
70	      warnings.push({
71	        type: 'unsupported',
72	        feature: 'seed',
73	        details: 'This model does not support the `seed` option.',
74	      });
75	    }
76	
77	    if (size != null) {
78	      warnings.push({
79	        type: 'unsupported',
80	        feature: 'size',
81	        details:
82	          'This model does not support the `size` option. Use `aspectRatio` instead.',
83	      });
84	    }
